import{_ as a,c as t,o as i,ag as n}from"./chunks/framework.ELrfyV9R.js";const c=JSON.parse('{"title":"SSH 一断，8 小时白跑：tmux 才是终端最值钱的保险","description":"","frontmatter":{},"headers":[],"relativePath":"ai/2026-03/2026-03-19-vvtest.md","filePath":"ai/2026-03/2026-03-19-vvtest.md","lastUpdated":1773929044000}'),e={name:"ai/2026-03/2026-03-19-vvtest.md"};function l(p,s,h,d,r,o){return i(),t("div",null,s[0]||(s[0]=[n(`<h1 id="ssh-一断-8-小时白跑-tmux-才是终端最值钱的保险" tabindex="-1">SSH 一断，8 小时白跑：tmux 才是终端最值钱的保险 <a class="header-anchor" href="#ssh-一断-8-小时白跑-tmux-才是终端最值钱的保险" aria-label="Permalink to &quot;SSH 一断，8 小时白跑：tmux 才是终端最值钱的保险&quot;">​</a></h1><blockquote><p>如果你跑过训练、部署过服务、在服务器上熬过夜，你迟早会明白：tmux 不是“高阶技巧”，而是防止血压飙升的基本配置。</p></blockquote><hr><h2 id="_01-它到底是什么" tabindex="-1">01 它到底是什么？ <a class="header-anchor" href="#_01-它到底是什么" aria-label="Permalink to &quot;01 它到底是什么？&quot;">​</a></h2><p>我第一次认真学 tmux，不是为了“提升效率”，而是因为我把一个跑了 <strong>7 小时 43 分钟</strong> 的训练任务亲手弄丢了。</p><p>那天我在服务器上挂着训练，去楼下买咖啡，WiFi 抖了一下，SSH 断开。我重新连回去的时候，终端干干净净，像什么都没发生过。那一刻我只有一个念头：<strong>这 7 个多小时，算是给服务器做慈善了。</strong></p><p>更糟的是，这不只是“浪费了一晚”。我原本第二天早上要拿这组结果继续调参，结果只能从头再跑一遍，后面的安排全部往后顺延。很多人真正破防的点，也不是任务挂了，而是你连昨天跑到哪一步、该从哪里接上，都得重新捡。</p><p>tmux 就是专门拿来解决这种“人还活着，任务先没了”的问题。它的全称是 <strong>Terminal Multiplexer</strong>，直译是&quot;终端复用器&quot;。但你没必要记这个名词，你只要记住一句人话：<strong>tmux 能把你的工作现场留在服务器里</strong>。哪怕你断网、合上电脑、SSH 掉线，里面的程序也会继续跑，你回来还能接着看、接着控。</p><p>如果你经常远程开发、跑脚本、训模型、部署服务，那 tmux 基本不是“学不学”的问题，而是你迟早要补的一课。区别只在于：<strong>你是今天学，还是等下一次事故之后再学。</strong></p><blockquote><p>💡 <strong>类比</strong></p><p>想象你在公司有一张大桌子，桌上摆着好几个不同项目的文件夹。你可以随时离开去吃饭，回来时桌子上的东西还在原地。tmux 就是这张永远不会被收拾的桌子——哪怕你断网、关电脑，你的&quot;工作现场&quot;都原封不动地保留着。</p></blockquote><hr><h2 id="_02-三个概念-搞懂就够了" tabindex="-1">02 三个概念，搞懂就够了 <a class="header-anchor" href="#_02-三个概念-搞懂就够了" aria-label="Permalink to &quot;02 三个概念，搞懂就够了&quot;">​</a></h2><p>tmux 有三层结构，从大到小依次是：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>tmux 服务器</span></span>
<span class="line"><span>├── 会话 Session  ← 一个项目 / 一个任务</span></span>
<span class="line"><span>│   ├── 窗口 Window   ← 一个标签页</span></span>
<span class="line"><span>│   │   ├── 面板 Pane  ← 一块分屏区域</span></span>
<span class="line"><span>│   │   └── 面板 Pane  ← 另一块分屏区域</span></span>
<span class="line"><span>│   └── 窗口 Window</span></span>
<span class="line"><span>└── 会话 Session  ← 另一个项目</span></span></code></pre></div><table tabindex="0"><thead><tr><th>概念</th><th>类比</th><th>说明</th></tr></thead><tbody><tr><td><strong>Session 会话</strong></td><td>一个项目文件夹</td><td>对应一个项目。断开连接后，会话继续在后台存活，随时可以重新连上。</td></tr><tr><td><strong>Window 窗口</strong></td><td>浏览器标签页</td><td>类似浏览器标签页。一个会话里可以有多个窗口，随时切换。</td></tr><tr><td><strong>Pane 面板</strong></td><td>分屏区域</td><td>把窗口分割成多块区域，每块都是一个独立的终端，同时运行不同程序。</td></tr></tbody></table><hr><h2 id="_03-五分钟上手-记住这些就行" tabindex="-1">03 五分钟上手，记住这些就行 <a class="header-anchor" href="#_03-五分钟上手-记住这些就行" aria-label="Permalink to &quot;03 五分钟上手，记住这些就行&quot;">​</a></h2><p>tmux 所有操作都靠一个<strong>前缀键</strong>触发，默认是 <code>Ctrl + b</code>。先按这个组合键，松开，再按其他键来执行操作。就像 Word 里的 Ctrl，是所有快捷键的&quot;前置动作&quot;。</p><h3 id="启动一个有名字的会话" tabindex="-1">启动一个有名字的会话 <a class="header-anchor" href="#启动一个有名字的会话" aria-label="Permalink to &quot;启动一个有名字的会话&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 创建名为 &quot;myproject&quot; 的会话</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> myproject</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 现在你在 tmux 里了，可以正常工作</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server.py</span></span></code></pre></div><h3 id="最常用快捷键一览" tabindex="-1">最常用快捷键一览 <a class="header-anchor" href="#最常用快捷键一览" aria-label="Permalink to &quot;最常用快捷键一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>快捷键</th><th>作用</th></tr></thead><tbody><tr><td><code>Ctrl+b</code> 然后 <code>d</code></td><td><strong>分离会话</strong>（detach），程序继续后台运行</td></tr><tr><td><code>tmux attach -t myproject</code></td><td>重新连回刚才的会话</td></tr><tr><td><code>tmux ls</code></td><td>列出所有正在运行的会话</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>%</code></td><td><strong>左右分屏</strong>，左右各一个面板</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>&quot;</code></td><td><strong>上下分屏</strong></td></tr><tr><td><code>Ctrl+b</code> 然后 <code>方向键</code></td><td>在面板之间切换焦点</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>c</code></td><td>新建一个窗口</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>0~9</code></td><td>切换到对应编号的窗口</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>s</code></td><td>可视化选择会话</td></tr><tr><td><code>Ctrl+b</code> 然后 <code>x</code></td><td>关闭当前面板</td></tr></tbody></table><hr><h2 id="_04-真实场景-它能帮你做什么" tabindex="-1">04 真实场景：它能帮你做什么？ <a class="header-anchor" href="#_04-真实场景-它能帮你做什么" aria-label="Permalink to &quot;04 真实场景：它能帮你做什么？&quot;">​</a></h2><h3 id="🚂-场景一-长时间任务不怕断网" tabindex="-1">🚂 场景一：长时间任务不怕断网 <a class="header-anchor" href="#🚂-场景一-长时间任务不怕断网" aria-label="Permalink to &quot;🚂 场景一：长时间任务不怕断网&quot;">​</a></h3><p>假设你在服务器上跑一个机器学习模型训练，要跑 8 个小时。</p><ul><li><strong>以前：</strong> SSH 断了，任务就没了，哭都没用。你会一边重跑，一边在心里默默复盘“我为什么没早点学 tmux”。</li><li><strong>用 tmux 后：</strong> 在 tmux 里启动训练，然后按 <code>Ctrl+b d</code> 分离，关电脑回家。第二天再 SSH 上去，<code>tmux attach</code> 一下，8 小时的任务还在跑，结果就在那等着你。</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在 tmux 里启动训练</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> new</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> training</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">python</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> train.py</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --epochs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 断开连接（任务继续跑）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Ctrl+b d</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 第二天重新连上</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user@server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> training</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Epoch 98/100... loss: 0.0341  ← 任务还在！</span></span></code></pre></div><h3 id="🖥️-场景二-同时看日志-写代码-跑测试" tabindex="-1">🖥️ 场景二：同时看日志 + 写代码 + 跑测试 <a class="header-anchor" href="#🖥️-场景二-同时看日志-写代码-跑测试" aria-label="Permalink to &quot;🖥️ 场景二：同时看日志 + 写代码 + 跑测试&quot;">​</a></h3><p>开发时你经常需要同时做好几件事。用 tmux 分屏，一个面板跑开发服务器，一个面板看日志实时输出，一个面板继续写代码。</p><p>再也不用在 N 个终端窗口之间来回切换，<strong>一个屏幕搞定所有</strong>。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 左右分屏</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ctrl+b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> %</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 左边面板：运行开发服务器</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 切换到右边面板</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Ctrl+b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> →</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 右边面板：实时查看日志</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tail</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /var/log/app.log</span></span></code></pre></div><h3 id="👥-场景三-和同事共享终端" tabindex="-1">👥 场景三：和同事共享终端 <a class="header-anchor" href="#👥-场景三-和同事共享终端" aria-label="Permalink to &quot;👥 场景三：和同事共享终端&quot;">​</a></h3><p>远程协作时，你和同事可以同时 attach 到同一个 tmux 会话，看到相同的终端内容。这比&quot;截图发微信&quot;方便得多，非常适合远程 debug 或者演示。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 同事连上服务器后，执行：</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tmux</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> attach</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> demo</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # -r 表示只读模式</span></span></code></pre></div><h3 id="🤖-场景四-配合-ai-编程助手" tabindex="-1">🤖 场景四：配合 AI 编程助手 <a class="header-anchor" href="#🤖-场景四-配合-ai-编程助手" aria-label="Permalink to &quot;🤖 场景四：配合 AI 编程助手&quot;">​</a></h3><p>最近流行 AI 编程助手（比如 Codex CLI、Claude Code、Cursor 等）。有开发者专门研究发现：</p><p>让 AI 助手在 tmux 会话里启动后台服务，你可以<strong>实时看到服务器输出</strong>，也可以随时手动介入操作，比 AI 自己管理后台进程要透明可靠得多。</p><hr><h2 id="_04-5-一个很多人都会问的问题-为什么不是-nohup-或-screen" tabindex="-1">04.5 一个很多人都会问的问题：为什么不是 nohup 或 screen？ <a class="header-anchor" href="#_04-5-一个很多人都会问的问题-为什么不是-nohup-或-screen" aria-label="Permalink to &quot;04.5 一个很多人都会问的问题：为什么不是 nohup 或 screen？&quot;">​</a></h2><p>第一次接触服务器后台任务时，很多人都会先学到 <code>nohup</code>。它当然能用，但它更像“先别死”，不是“我还要回来继续工作”。这两者差别很大。</p><table tabindex="0"><thead><tr><th>工具</th><th>更像什么</th><th>适合什么场景</th><th>局限在哪里</th></tr></thead><tbody><tr><td><code>nohup</code></td><td>把命令扔到后台</td><td>简单、一次性的后台运行</td><td>很难优雅地回到原来的工作现场，日志、交互、上下文都比较零碎</td></tr><tr><td><code>screen</code></td><td>老牌可重连终端</td><td>能断开再连</td><td>思路接近 tmux，但现在资料、配置体验和生态普遍不如 tmux 常见</td></tr><tr><td><code>tmux</code></td><td>可保存现场的工作台</td><td>长任务、分屏、多窗口、日志观察、手动接管</td><td>需要记住一套基本快捷键，但一旦习惯，回报很高</td></tr></tbody></table><blockquote><p>💡 <strong>类比</strong></p><p><code>nohup</code> 更像“把锅放小火上继续炖”；tmux 更像“整个厨房我先给你原样封存，回来灯还是亮的，锅还在火上，刀和案板都没动过”。</p></blockquote><hr><h2 id="_05-让-tmux-更好用的几个配置" tabindex="-1">05 让 tmux 更好用的几个配置 <a class="header-anchor" href="#_05-让-tmux-更好用的几个配置" aria-label="Permalink to &quot;05 让 tmux 更好用的几个配置&quot;">​</a></h2><p>tmux 有一个配置文件 <code>~/.tmux.conf</code>，几行配置就能让体验大幅提升：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 开启鼠标支持（可以用鼠标点击面板、拖动边框）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mouse</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> on</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 支持真彩色，让终端颜色更好看</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> default-terminal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;tmux-256color&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用更直观的按键分屏（| 是垂直分割，- 是水平分割）</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bind</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> split-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bind</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> -</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> split-window</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 增大历史记录行数</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> history-limit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10000</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 消除 Esc 键延迟（对 vim 用户很重要）</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -sg</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> escape-time</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0</span></span></code></pre></div><p>修改完后，在 tmux 里按 <code>Ctrl+b</code> 然后输入 <code>:source ~/.tmux.conf</code> 即可生效，不需要重启。</p><hr><h2 id="_06-遇到问题-先看这里" tabindex="-1">06 遇到问题？先看这里 <a class="header-anchor" href="#_06-遇到问题-先看这里" aria-label="Permalink to &quot;06 遇到问题？先看这里&quot;">​</a></h2><p><strong>Q：颜色显示不对、有乱码怎么办？</strong></p><p>在配置文件里加上 <code>set -g default-terminal &quot;tmux-256color&quot;</code>，并确保你的终端本身支持 256 色。</p><p><strong>Q：鼠标滚动没反应？</strong></p><p>先确认 <code>set -g mouse on</code> 已经写进配置文件，然后重新加载配置。如果还不行，可能是终端本身不支持，换用 iTerm2（Mac）或 Windows Terminal 试试。</p><p><strong>Q：会话突然显示 &quot;attached&quot; 无法连接？</strong></p><p>用 <code>tmux attach -d -t 会话名</code> 命令，<code>-d</code> 会先把其他客户端踢下线，然后你就能连上了。</p><p><strong>Q：tmux 和直接用终端标签页有什么区别？</strong></p><p>终端标签页依赖本地终端软件，<strong>断开 SSH 就丢失了</strong>。tmux 运行在服务器上，和你的连接状态无关，这是最本质的区别。本地开发的话，标签页可能够用；远程服务器上，强烈建议用 tmux。</p><hr><h2 id="_07-如果你今晚就要跑一个长任务-从这里开始" tabindex="-1">07 如果你今晚就要跑一个长任务，从这里开始 <a class="header-anchor" href="#_07-如果你今晚就要跑一个长任务-从这里开始" aria-label="Permalink to &quot;07 如果你今晚就要跑一个长任务，从这里开始&quot;">​</a></h2><p>别试图一口气学完所有功能。你只要先把下面这几步走通，下一次 SSH 抽风时，你会真心感谢现在的自己。</p><ol><li><p><strong>装好 tmux</strong></p><ul><li>Ubuntu/Debian：<code>sudo apt install tmux</code></li><li>macOS：<code>brew install tmux</code></li></ul></li><li><p><strong>用它启动你下一个需要持续运行的任务</strong></p><ul><li><code>tmux new -s 任务名</code>，跑程序，然后 <code>Ctrl+b d</code> 分离</li></ul></li><li><p><strong>加上鼠标支持</strong></p><ul><li>把 <code>set -g mouse on</code> 写进 <code>~/.tmux.conf</code>，立刻舒服很多</li></ul></li><li><p><strong>尝试分屏</strong></p><ul><li>用 <code>Ctrl+b %</code> 左右分屏，一边跑程序一边看日志</li></ul></li><li><p><strong>探索插件（可选）</strong></p><ul><li>安装 <strong>tmux-resurrect</strong> 可以保存和恢复整个 tmux 布局，即使服务器重启也没问题</li></ul></li></ol><blockquote><p>💡 tmux 的学习曲线不高，但收益非常具体：少一次重跑任务，少一次熬夜盯日志，少一次“我明明已经快跑完了”的崩溃。它不像炫技工具，更像是服务器工作流里那种<strong>出事前你嫌麻烦，出事后你恨没早点装</strong>的东西。</p></blockquote><p><strong>最后留个问题：</strong> 你最肉疼的一次“断连事故”是哪种？</p><ul><li>A. 训练跑了一夜，早上起来发现早停在第 2 小时</li><li>B. 部署做到一半掉线，线上和本地状态全乱了</li><li>C. 服务还活着，但日志窗口没了，不敢乱动</li><li>D. SSH 一断，之前开的上下文、命令、排查路径全部清空</li></ul><p>如果你是 D，tmux 对你基本不是“可选工具”，而是迟早要装的基础设施。</p><p>再追问一句：你是 <strong>“先学 tmux 派”</strong>，还是 <strong>“吃过断连亏才补票派”</strong>？大多数人其实都是后者。</p><hr><p><em>参考：<a href="https://github.com/tmux/tmux/wiki" target="_blank" rel="noreferrer">tmux 官方文档</a> · <a href="https://tmuxcheatsheet.com/" target="_blank" rel="noreferrer">tmux 速查表</a></em></p>`,69)]))}const g=a(e,[["render",l]]);export{c as __pageData,g as default};
